using AmbientEffectsEngine.Services;
using AmbientEffectsEngine.Services.Capture;
using AmbientEffectsEngine.Services.Processing;
using AmbientEffectsEngine.Services.Rendering;
using AmbientEffectsEngine.ViewModels;
using AmbientEffectsEngine.Views;
using Microsoft.Extensions.DependencyInjection;
using System.Windows;
using WpfApplication = System.Windows.Application;

namespace AmbientEffectsEngine;

public partial class App : WpfApplication
{
    private SystemTrayService? _systemTrayService;
    private ServiceProvider? _serviceProvider;

    protected override void OnStartup(StartupEventArgs e)
    {
        base.OnStartup(e);

        // Configure services
        var services = new ServiceCollection();
        ConfigureServices(services);
        _serviceProvider = services.BuildServiceProvider();

        // Initialize system tray
        _systemTrayService = new SystemTrayService();
        _systemTrayService.Initialize();

        // Start screen capture service
        var screenCaptureService = _serviceProvider.GetRequiredService<IScreenCaptureService>();
        screenCaptureService.Start();

        // Start audio capture service
        var audioCaptureService = _serviceProvider.GetRequiredService<IAudioCaptureService>();
        audioCaptureService.Start();

        // Start data processing service
        var dataProcessingService = _serviceProvider.GetRequiredService<IDataProcessingService>();
        dataProcessingService.Start();

        // Create and show main window
        var mainWindow = _serviceProvider.GetRequiredService<MainWindow>();
        mainWindow.Show();
    }

    private void ConfigureServices(ServiceCollection services)
    {
        // Register services
        services.AddSingleton<IScreenCaptureService, ScreenCaptureService>();
        services.AddSingleton<IAudioCaptureService, AudioCaptureService>();
        services.AddSingleton<IDataProcessingService, DataProcessingService>();
        services.AddSingleton<IEffectFactory, EffectFactory>();
        services.AddSingleton<IEffectsRenderingService, EffectsRenderingService>();
        services.AddSingleton<ISettingsService, SettingsService>();
        services.AddSingleton<IMonitorDetectionService, MonitorDetectionService>();

        // Register ViewModels
        services.AddTransient<MainViewModel>();
        services.AddTransient<MonitorSetupViewModel>();

        // Register Views
        services.AddTransient<MainWindow>(provider => new MainWindow(
            provider.GetRequiredService<MainViewModel>(),
            provider));
        services.AddTransient<MonitorSetupPage>();
    }

    protected override void OnExit(ExitEventArgs e)
    {
        // Stop screen capture
        var screenCaptureService = _serviceProvider?.GetService<IScreenCaptureService>();
        screenCaptureService?.Stop();

        // Stop audio capture
        var audioCaptureService = _serviceProvider?.GetService<IAudioCaptureService>();
        audioCaptureService?.Stop();

        // Stop data processing service
        var dataProcessingService = _serviceProvider?.GetService<IDataProcessingService>();
        dataProcessingService?.Stop();

        // Stop effects rendering service
        var effectsRenderingService = _serviceProvider?.GetService<IEffectsRenderingService>();
        effectsRenderingService?.Stop();

        // Stop monitor detection service
        var monitorDetectionService = _serviceProvider?.GetService<IMonitorDetectionService>();
        if (monitorDetectionService is IDisposable disposableService)
        {
            disposableService.Dispose();
        }

        _systemTrayService?.Shutdown();
        _serviceProvider?.Dispose();
        base.OnExit(e);
    }
}

using System.Windows.Controls;
using AmbientEffectsEngine.ViewModels;

namespace AmbientEffectsEngine.Views
{
    public partial class MonitorSetupPage : Page
    {
        public MonitorSetupPage()
        {
            InitializeComponent();
        }

        public MonitorSetupPage(MonitorSetupViewModel viewModel) : this()
        {
            DataContext = viewModel;
        }
    }
}

using System;
using System.Windows;
using System.Windows.Navigation;
using AmbientEffectsEngine.ViewModels;
using Microsoft.Extensions.DependencyInjection;

namespace AmbientEffectsEngine.Views;

public partial class MainWindow : Window
{
    private MainViewModel? _viewModel;
    private readonly IServiceProvider _serviceProvider;

    public MainWindow(MainViewModel viewModel, IServiceProvider serviceProvider)
    {
        InitializeComponent();
        _viewModel = viewModel ?? throw new ArgumentNullException(nameof(viewModel));
        _serviceProvider = serviceProvider ?? throw new ArgumentNullException(nameof(serviceProvider));
        DataContext = _viewModel;
    }

    private void MonitorSetupButton_Click(object sender, RoutedEventArgs e)
    {
        try
        {
            var monitorSetupViewModel = _serviceProvider.GetRequiredService<MonitorSetupViewModel>();
            var monitorSetupPage = new MonitorSetupPage(monitorSetupViewModel);

            var monitorSetupWindow = new Window
            {
                Title = "Monitor Setup",
                Content = monitorSetupPage,
                Width = 800,
                Height = 600,
                MinWidth = 600,
                MinHeight = 400,
                WindowStartupLocation = WindowStartupLocation.CenterOwner,
                Owner = this
            };

            monitorSetupWindow.ShowDialog();
        }
        catch (Exception ex)
        {
            System.Windows.MessageBox.Show($"Error opening Monitor Setup: {ex.Message}", "Error", MessageBoxButton.OK, MessageBoxImage.Error);
        }
    }

    protected override void OnClosed(EventArgs e)
    {
        _viewModel = null;
        base.OnClosed(e);
    }
}

using System;
using System.Collections.Generic;
using System.Collections.ObjectModel;
using System.ComponentModel;
using System.Linq;
using System.Runtime.CompilerServices;
using System.Threading.Tasks;
using AmbientEffectsEngine.Models;
using AmbientEffectsEngine.Services;
using AmbientEffectsEngine.Services.Rendering;

namespace AmbientEffectsEngine.ViewModels
{
    public class MonitorSetupViewModel : INotifyPropertyChanged
    {
        private readonly IMonitorDetectionService _monitorDetectionService;
        private readonly ISettingsService _settingsService;
        private readonly IEffectsRenderingService _effectsRenderingService;
        private bool _isLoading;

        public event PropertyChangedEventHandler? PropertyChanged;

        public ObservableCollection<MonitorSelectionViewModel> Monitors { get; }

        public bool IsLoading
        {
            get => _isLoading;
            set
            {
                if (_isLoading != value)
                {
                    _isLoading = value;
                    OnPropertyChanged();
                }
            }
        }

        public MonitorSetupViewModel(IMonitorDetectionService monitorDetectionService, ISettingsService settingsService, IEffectsRenderingService effectsRenderingService)
        {
            _monitorDetectionService = monitorDetectionService ?? throw new ArgumentNullException(nameof(monitorDetectionService));
            _settingsService = settingsService ?? throw new ArgumentNullException(nameof(settingsService));
            _effectsRenderingService = effectsRenderingService ?? throw new ArgumentNullException(nameof(effectsRenderingService));

            Monitors = new ObservableCollection<MonitorSelectionViewModel>();

            // Subscribe to monitor configuration changes
            _monitorDetectionService.MonitorConfigurationChanged += OnMonitorConfigurationChanged;

            // Start monitoring for changes
            _monitorDetectionService.StartMonitoring();

            // Load monitors and settings
            _ = LoadMonitorsAsync();
        }

        public async Task LoadMonitorsAsync()
        {
            IsLoading = true;

            try
            {
                // Get connected monitors
                var connectedMonitors = await _monitorDetectionService.GetConnectedMonitorsAsync();

                // Load saved settings to get selected monitor IDs
                var settings = await _settingsService.LoadAsync();
                var selectedMonitorIds = settings.TargetMonitorIds ?? new List<string>();

                // Clear existing monitors
                Monitors.Clear();

                // Create monitor selection view models
                foreach (var monitor in connectedMonitors)
                {
                    var monitorVM = new MonitorSelectionViewModel(monitor)
                    {
                        IsSelected = selectedMonitorIds.Contains(monitor.Id) && !monitor.IsPrimary
                    };

                    // Subscribe to selection changes
                    monitorVM.PropertyChanged += OnMonitorSelectionChanged;

                    Monitors.Add(monitorVM);
                }
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"Error loading monitors: {ex.Message}");
            }
            finally
            {
                IsLoading = false;
            }
        }

        private async void OnMonitorSelectionChanged(object? sender, PropertyChangedEventArgs e)
        {
            if (e.PropertyName == nameof(MonitorSelectionViewModel.IsSelected))
            {
                await SaveSelectionAsync();
            }
        }

        private async Task SaveSelectionAsync()
        {
            try
            {
                var settings = await _settingsService.LoadAsync();

                // Get selected monitor IDs (excluding primary monitors)
                var selectedMonitorIds = Monitors
                    .Where(m => m.IsSelected && !m.Monitor.IsPrimary)
                    .Select(m => m.Monitor.Id)
                    .ToList();

                settings.TargetMonitorIds = selectedMonitorIds;

                await _settingsService.SaveAsync(settings);

                // Apply monitor selections to effects rendering service immediately
                _effectsRenderingService.SetTargetMonitors(selectedMonitorIds);
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"Error saving monitor selection: {ex.Message}");
            }
        }

        private async void OnMonitorConfigurationChanged(object? sender, MonitorConfigurationChangedEventArgs e)
        {
            // Reload monitors when configuration changes
            await LoadMonitorsAsync();
        }

        protected virtual void OnPropertyChanged([CallerMemberName] string? propertyName = null)
        {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
        }
    }

    public class MonitorSelectionViewModel : INotifyPropertyChanged
    {
        private bool _isSelected;

        public event PropertyChangedEventHandler? PropertyChanged;

        public DisplayMonitor Monitor { get; }

        public bool IsSelected
        {
            get => _isSelected;
            set
            {
                if (_isSelected != value && !Monitor.IsPrimary)
                {
                    _isSelected = value;
                    OnPropertyChanged();
                }
            }
        }

        public bool CanSelect => !Monitor.IsPrimary;

        public string DisplayName => Monitor.IsPrimary ? $"{Monitor.Name} (Primary)" : Monitor.Name;

        public MonitorSelectionViewModel(DisplayMonitor monitor)
        {
            Monitor = monitor ?? throw new ArgumentNullException(nameof(monitor));
        }

        protected virtual void OnPropertyChanged([CallerMemberName] string? propertyName = null)
        {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
        }
    }
}

using System;
using System.Collections.ObjectModel;
using System.ComponentModel;
using System.Linq;
using System.Runtime.CompilerServices;
using AmbientEffectsEngine.Models;
using AmbientEffectsEngine.Services;
using AmbientEffectsEngine.Services.Processing;
using AmbientEffectsEngine.Services.Rendering;

namespace AmbientEffectsEngine.ViewModels
{
    public class MainViewModel : INotifyPropertyChanged
    {
        private readonly IEffectsRenderingService? _effectsRenderingService;
        private readonly IEffectFactory? _effectFactory;
        private readonly ISettingsService? _settingsService;
        private readonly IDataProcessingService? _dataProcessingService;
        private bool _isEnabled;
        private EffectStyle _selectedEffect = new EffectStyle();
        private float _audioSensitivity;

        public event PropertyChangedEventHandler? PropertyChanged;

        public bool IsEnabled
        {
            get => _isEnabled;
            set
            {
                if (_isEnabled != value)
                {
                    _isEnabled = value;
                    OnPropertyChanged();
                    UpdateEffectsRenderingState();
                    SaveSettingsAsync();
                }
            }
        }

        public EffectStyle SelectedEffect
        {
            get => _selectedEffect;
            set
            {
                if (_selectedEffect != value)
                {
                    _selectedEffect = value;
                    OnPropertyChanged();
                    OnEffectSelectionChanged();
                }
            }
        }

        public float AudioSensitivity
        {
            get => _audioSensitivity;
            set
            {
                if (Math.Abs(_audioSensitivity - value) > 0.001f)
                {
                    _audioSensitivity = Math.Clamp(value, 0.0f, 1.0f);
                    OnPropertyChanged();
                    OnAudioSensitivityChanged();
                }
            }
        }

        public ObservableCollection<EffectStyle> AvailableEffects { get; }

        public MainViewModel(IEffectsRenderingService? effectsRenderingService = null, 
                            IEffectFactory? effectFactory = null, 
                            ISettingsService? settingsService = null, 
                            IDataProcessingService? dataProcessingService = null)
        {
            _effectsRenderingService = effectsRenderingService;
            _effectFactory = effectFactory;
            _settingsService = settingsService;
            _dataProcessingService = dataProcessingService;

            // Initialize available effects from factory
            AvailableEffects = new ObservableCollection<EffectStyle>();
            LoadAvailableEffects();

            // Load settings or use defaults
            LoadSettingsAsync();
        }

        private void LoadAvailableEffects()
        {
            AvailableEffects.Clear();

            if (_effectFactory != null)
            {
                // Get available effects from the factory and create effect instances to get their metadata
                foreach (var effectId in _effectFactory.GetAvailableEffectIds())
                {
                    try
                    {
                        using var effect = _effectFactory.CreateEffect(effectId);
                        AvailableEffects.Add(new EffectStyle
                        {
                            Id = effect.EffectId,
                            Name = effect.Name,
                            Description = effect.Description
                        });
                    }
                    catch (Exception ex)
                    {
                        System.Diagnostics.Debug.WriteLine($"Failed to load effect '{effectId}': {ex.Message}");
                    }
                }
            }

            // Fallback to hardcoded effects if factory is not available
            if (AvailableEffects.Count == 0)
            {
                AvailableEffects.Add(new EffectStyle { Id = "softglow", Name = "Soft Glow", Description = "Ambient glow effect" });
                AvailableEffects.Add(new EffectStyle { Id = "generativevisualizer", Name = "Generative Visualizer", Description = "Dynamic particle-based visualization" });
            }
        }

        private async void LoadSettingsAsync()
        {
            if (_settingsService == null)
            {
                // Use defaults if no settings service
                _isEnabled = false;
                _audioSensitivity = 0.5f;
                _selectedEffect = AvailableEffects.FirstOrDefault(e => e.Id == "softglow") ?? AvailableEffects.FirstOrDefault() ?? new EffectStyle();
                return;
            }

            try
            {
                var settings = await _settingsService.LoadAsync();

                _isEnabled = settings.IsEnabled;
                _audioSensitivity = Math.Clamp(settings.AudioSensitivity, 0.0f, 1.0f);
                _selectedEffect = AvailableEffects.FirstOrDefault(e => e.Id == settings.SelectedEffectId) 
                                ?? AvailableEffects.FirstOrDefault() ?? new EffectStyle();

                // Update data processing service with loaded sensitivity
                if (_dataProcessingService != null)
                {
                    _dataProcessingService.AudioSensitivity = _audioSensitivity;
                }

                // Apply monitor selections to effects rendering service
                if (_effectsRenderingService != null && settings.TargetMonitorIds != null)
                {
                    _effectsRenderingService.SetTargetMonitors(settings.TargetMonitorIds);
                }

                // Notify UI of loaded values
                OnPropertyChanged(nameof(IsEnabled));
                OnPropertyChanged(nameof(AudioSensitivity));
                OnPropertyChanged(nameof(SelectedEffect));
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"Error loading settings: {ex.Message}");

                // Fallback to defaults
                _isEnabled = false;
                _audioSensitivity = 0.5f;
                _selectedEffect = AvailableEffects.FirstOrDefault(e => e.Id == "softglow") ?? AvailableEffects.FirstOrDefault() ?? new EffectStyle();
            }
        }

        private async void SaveSettingsAsync()
        {
            if (_settingsService == null) return;

            try
            {
                var settings = new ApplicationSettings
                {
                    IsEnabled = _isEnabled,
                    SelectedEffectId = _selectedEffect?.Id ?? "softglow",
                    AudioSensitivity = _audioSensitivity,
                    SourceMonitorId = string.Empty,
                    TargetMonitorIds = new System.Collections.Generic.List<string>()
                };

                await _settingsService.SaveAsync(settings);
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"Error saving settings: {ex.Message}");
            }
        }

        private void OnEffectSelectionChanged()
        {
            if (_effectsRenderingService == null || _selectedEffect == null) return;

            try
            {
                _effectsRenderingService.SetCurrentEffect(_selectedEffect.Id);
                SaveSettingsAsync();
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"Error changing effect to '{_selectedEffect.Id}': {ex.Message}");
            }
        }

        private void OnAudioSensitivityChanged()
        {
            if (_dataProcessingService != null)
            {
                _dataProcessingService.AudioSensitivity = _audioSensitivity;
            }

            SaveSettingsAsync();
        }

        private void UpdateEffectsRenderingState()
        {
            if (_effectsRenderingService == null) return;

            try
            {
                if (_isEnabled)
                {
                    _effectsRenderingService.Start();
                }
                else
                {
                    _effectsRenderingService.Stop();
                }
            }
            catch (Exception ex)
            {
                // Show error to user instead of hiding it
                System.Diagnostics.Debug.WriteLine($"Error updating effects rendering state: {ex.Message}");
                System.Windows.MessageBox.Show($"Error starting ambient effects: {ex.Message}\n\nDetails: {ex.StackTrace}", 
                    "Effects Error", System.Windows.MessageBoxButton.OK, System.Windows.MessageBoxImage.Error);
            }
        }

        protected virtual void OnPropertyChanged([CallerMemberName] string? propertyName = null)
        {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
        }
    }
}

using System.Drawing;
using System.Windows.Forms;

namespace AmbientEffectsEngine.Services;

public class SystemTrayService : ISystemTrayService
{
    private NotifyIcon? _notifyIcon;

    public void Initialize()
    {
        // Create the system tray icon
        _notifyIcon = new NotifyIcon
        {
            Text = "Ambient Effects Engine",
            Visible = true,
            Icon = SystemIcons.Application // Use built-in icon for now
        };

        // Create context menu
        var contextMenu = new ContextMenuStrip();
        contextMenu.Items.Add("Show", null, (s, e) => ShowMainWindow());
        contextMenu.Items.Add("Hide", null, (s, e) => HideMainWindow());
        contextMenu.Items.Add("-");
        contextMenu.Items.Add("Exit", null, (s, e) => System.Windows.Application.Current.Shutdown());

        _notifyIcon.ContextMenuStrip = contextMenu;
        _notifyIcon.DoubleClick += (s, e) => ShowMainWindow();
    }

    public void ShowMainWindow()
    {
        var mainWindow = System.Windows.Application.Current.MainWindow;
        if (mainWindow != null)
        {
            mainWindow.Show();
            mainWindow.WindowState = System.Windows.WindowState.Normal;
            mainWindow.Activate();
        }
    }

    public void HideMainWindow()
    {
        var mainWindow = System.Windows.Application.Current.MainWindow;
        mainWindow?.Hide();
    }

    public void Shutdown()
    {
        _notifyIcon?.Dispose();
        _notifyIcon = null;
    }
}

using System;
using System.IO;
using System.Text.Json;
using System.Threading.Tasks;
using AmbientEffectsEngine.Models;

namespace AmbientEffectsEngine.Services
{
    public class SettingsService : ISettingsService
    {
        private readonly string _settingsDirectoryPath;
        private readonly string _settingsFilePath;
        private readonly string _backupFilePath;

        public SettingsService() : this(Path.Combine(
            Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
            "AmbientEffectsEngine"))
        {
        }

        // Constructor for testing with custom directory
        internal SettingsService(string settingsDirectory)
        {
            _settingsDirectoryPath = settingsDirectory;
            _settingsFilePath = Path.Combine(_settingsDirectoryPath, "settings.json");
            _backupFilePath = Path.Combine(_settingsDirectoryPath, "settings.backup.json");
        }

        public async Task<ApplicationSettings> LoadAsync()
        {
            try
            {
                if (!File.Exists(_settingsFilePath))
                {
                    return GetDefaults();
                }

                var json = await File.ReadAllTextAsync(_settingsFilePath);
                var settings = JsonSerializer.Deserialize<ApplicationSettings>(json);

                return settings ?? GetDefaults();
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"Failed to load settings: {ex.Message}");

                // Try to load from backup
                if (File.Exists(_backupFilePath))
                {
                    try
                    {
                        var backupJson = await File.ReadAllTextAsync(_backupFilePath);
                        var backupSettings = JsonSerializer.Deserialize<ApplicationSettings>(backupJson);
                        return backupSettings ?? GetDefaults();
                    }
                    catch (Exception backupEx)
                    {
                        System.Diagnostics.Debug.WriteLine($"Failed to load backup settings: {backupEx.Message}");
                    }
                }

                return GetDefaults();
            }
        }

        public async Task SaveAsync(ApplicationSettings settings)
        {
            ArgumentNullException.ThrowIfNull(settings);

            try
            {
                // Ensure directory exists
                Directory.CreateDirectory(_settingsDirectoryPath);

                // Create backup if settings file exists
                if (File.Exists(_settingsFilePath))
                {
                    File.Copy(_settingsFilePath, _backupFilePath, overwrite: true);
                }

                var json = JsonSerializer.Serialize(settings, new JsonSerializerOptions
                {
                    WriteIndented = true
                });

                await File.WriteAllTextAsync(_settingsFilePath, json);
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"Failed to save settings: {ex.Message}");
                throw;
            }
        }

        public ApplicationSettings GetDefaults()
        {
            return new ApplicationSettings
            {
                IsEnabled = false,
                SelectedEffectId = "softglow",
                AudioSensitivity = 0.5f,
                SourceMonitorId = string.Empty,
                TargetMonitorIds = new System.Collections.Generic.List<string>()
            };
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Runtime.InteropServices;
using System.Threading.Tasks;
using AmbientEffectsEngine.Models;

namespace AmbientEffectsEngine.Services
{
    public class MonitorDetectionService : IMonitorDetectionService, IDisposable
    {
        private bool _isMonitoring;
        private bool _disposed;

        public event EventHandler<MonitorConfigurationChangedEventArgs>? MonitorConfigurationChanged;

        public async Task<IEnumerable<DisplayMonitor>> GetConnectedMonitorsAsync()
        {
            return await Task.Run(() =>
            {
                var monitors = new List<DisplayMonitor>();
                var primaryMonitorHandle = GetPrimaryMonitorHandle();

                EnumDisplayMonitors(IntPtr.Zero, IntPtr.Zero, MonitorEnumProc, IntPtr.Zero);

                bool MonitorEnumProc(IntPtr hMonitor, IntPtr hdcMonitor, IntPtr lprcMonitor, IntPtr dwData)
                {
                    var monitorInfo = new MONITORINFOEX();
                    monitorInfo.cbSize = Marshal.SizeOf(monitorInfo);

                    if (GetMonitorInfo(hMonitor, ref monitorInfo))
                    {
                        var monitor = new DisplayMonitor
                        {
                            Id = monitorInfo.szDevice,
                            Name = monitorInfo.szDevice,
                            IsPrimary = hMonitor == primaryMonitorHandle
                        };
                        monitors.Add(monitor);
                    }

                    return true;
                }

                return monitors.AsEnumerable();
            });
        }

        public void StartMonitoring()
        {
            if (_isMonitoring || _disposed)
                return;

            // For now, just mark as monitoring without setting up actual change detection
            // In a real implementation, this would set up a message window to receive WM_DISPLAYCHANGE
            // Since display change monitoring is complex and not critical for basic functionality,
            // we'll implement a simplified version that can be enhanced later
            _isMonitoring = true;
        }

        public void StopMonitoring()
        {
            if (!_isMonitoring)
                return;

            _isMonitoring = false;
        }


        private IntPtr GetPrimaryMonitorHandle()
        {
            const int MONITOR_DEFAULTTOPRIMARY = 1;
            return MonitorFromPoint(new POINT { x = 0, y = 0 }, MONITOR_DEFAULTTOPRIMARY);
        }

        public void Dispose()
        {
            if (_disposed)
                return;

            StopMonitoring();
            _disposed = true;
        }

        #region Windows API Declarations

        [DllImport("user32.dll")]
        private static extern bool EnumDisplayMonitors(IntPtr hdc, IntPtr lprcClip,
            EnumDisplayMonitorsDelegate lpfnEnum, IntPtr dwData);

        [DllImport("user32.dll", CharSet = CharSet.Unicode)]
        private static extern bool GetMonitorInfo(IntPtr hMonitor, ref MONITORINFOEX lpmi);

        [DllImport("user32.dll")]
        private static extern IntPtr MonitorFromPoint(POINT pt, int dwFlags);

        private delegate bool EnumDisplayMonitorsDelegate(IntPtr hMonitor, IntPtr hdcMonitor,
            IntPtr lprcMonitor, IntPtr dwData);

        [StructLayout(LayoutKind.Sequential)]
        private struct POINT
        {
            public int x;
            public int y;
        }

        [StructLayout(LayoutKind.Sequential)]
        private struct RECT
        {
            public int left;
            public int top;
            public int right;
            public int bottom;
        }

        [StructLayout(LayoutKind.Sequential, CharSet = CharSet.Unicode)]
        private struct MONITORINFOEX
        {
            public int cbSize;
            public RECT rcMonitor;
            public RECT rcWork;
            public int dwFlags;
            [MarshalAs(UnmanagedType.ByValTStr, SizeConst = 32)]
            public string szDevice;
        }

        #endregion
    }
}

namespace AmbientEffectsEngine.Services;

public interface ISystemTrayService
{
    void Initialize();
    void ShowMainWindow();
    void HideMainWindow();
    void Shutdown();
}

using System.Threading.Tasks;
using AmbientEffectsEngine.Models;

namespace AmbientEffectsEngine.Services
{
    public interface ISettingsService
    {
        Task<ApplicationSettings> LoadAsync();
        Task SaveAsync(ApplicationSettings settings);
        ApplicationSettings GetDefaults();
    }
}

using System;
using System.Collections.Generic;
using System.Threading.Tasks;
using AmbientEffectsEngine.Models;

namespace AmbientEffectsEngine.Services
{
    public interface IMonitorDetectionService
    {
        /// <summary>
        /// Gets all connected monitors with their display information
        /// </summary>
        /// <returns>List of DisplayMonitor objects representing connected displays</returns>
        Task<IEnumerable<DisplayMonitor>> GetConnectedMonitorsAsync();

        /// <summary>
        /// Event fired when monitor configuration changes (monitors connected/disconnected)
        /// </summary>
        event EventHandler<MonitorConfigurationChangedEventArgs>? MonitorConfigurationChanged;

        /// <summary>
        /// Starts monitoring for display configuration changes
        /// </summary>
        void StartMonitoring();

        /// <summary>
        /// Stops monitoring for display configuration changes
        /// </summary>
        void StopMonitoring();
    }

    public class MonitorConfigurationChangedEventArgs : EventArgs
    {
        public IEnumerable<DisplayMonitor> ConnectedMonitors { get; }

        public MonitorConfigurationChangedEventArgs(IEnumerable<DisplayMonitor> connectedMonitors)
        {
            ConnectedMonitors = connectedMonitors ?? throw new ArgumentNullException(nameof(connectedMonitors));
        }
    }
}

using System;
using System.Drawing;

namespace AmbientEffectsEngine.Models
{
    public class ProcessedData
    {
        public Color DominantColor { get; set; }
        public float AudioIntensity { get; set; } // 0.0-1.0 normalized range
        public DateTime Timestamp { get; set; }

        /// <summary>
        /// Audio intensity as a percentage (0-100 scale) for UI display purposes
        /// </summary>
        public float AudioIntensityPercent => AudioIntensity * 100.0f;

        public ProcessedData(Color dominantColor, float audioIntensity, DateTime timestamp)
        {
            DominantColor = dominantColor;
            AudioIntensity = Math.Clamp(audioIntensity, 0.0f, 1.0f);
            Timestamp = timestamp;
        }

        public ProcessedData() : this(Color.Black, 0.0f, DateTime.UtcNow)
        {
        }
    }
}

namespace AmbientEffectsEngine.Models
{
    public class EffectStyle
    {
        public string Id { get; set; } = string.Empty;
        public string Name { get; set; } = string.Empty;
        public string Description { get; set; } = string.Empty;
    }
}

namespace AmbientEffectsEngine.Models
{
    public class DisplayMonitor
    {
        public string Id { get; set; } = string.Empty;
        public string Name { get; set; } = string.Empty;
