using System;
using System.Diagnostics;
using System.Threading;
using NAudio.Wasapi;
using NAudio.Wave;

namespace AmbientEffectsEngine.Services.Capture
{
    public class AudioCaptureService : IAudioCaptureService
    {
        private WasapiLoopbackCapture? _capture;
        private bool _disposed;
        private readonly object _lock = new object();
        private volatile bool _isCapturing;
        private int _audioDataCount;

        public event EventHandler<AudioDataEventArgs>? AudioDataAvailable;

        public bool IsCapturing 
        { 
            get 
            { 
                lock (_lock)
                {
                    return _isCapturing && _capture != null;
                }
            } 
        }

        public void Start()
        {
            lock (_lock)
            {
                if (_disposed)
                    throw new ObjectDisposedException(nameof(AudioCaptureService));

                if (_isCapturing || _capture != null)
                    return;

                try
                {
                    _capture = new WasapiLoopbackCapture();
                    _capture.DataAvailable += OnDataAvailable;
                    _capture.RecordingStopped += OnRecordingStopped;

                    Debug.WriteLine($"[AudioCapture] Starting audio capture - Format: {_capture.WaveFormat}");
                    _capture.StartRecording();
                    _isCapturing = true;
                    _audioDataCount = 0;
                    Debug.WriteLine("[AudioCapture] Audio capture started successfully");
                }
                catch (Exception ex)
                {
                    Debug.WriteLine($"[AudioCapture] Failed to start audio capture: {ex.Message}");
                    _capture?.Dispose();
                    _capture = null;
                    _isCapturing = false;
                    throw new InvalidOperationException("Failed to start audio capture.", ex);
                }
            }
        }

        public void Stop()
        {
            lock (_lock)
            {
                if (!_isCapturing || _capture == null)
                    return;

                try
                {
                    Debug.WriteLine("[AudioCapture] Stopping audio capture");
                    _capture.StopRecording();
                }
                catch (Exception ex)
                {
                    Debug.WriteLine($"[AudioCapture] Exception during stop: {ex.Message}");
                }
                finally
                {
                    _isCapturing = false;
                    Debug.WriteLine($"[AudioCapture] Audio capture stopped. Total data events received: {_audioDataCount}");
                }
            }
        }

        private void OnDataAvailable(object? sender, WaveInEventArgs e)
        {
            if (_disposed || e.Buffer == null || e.BytesRecorded == 0)
                return;

            try
            {
                _audioDataCount++;
                var volumeLevel = CalculateVolumeLevel(e.Buffer, e.BytesRecorded);
                var sampleRate = _capture?.WaveFormat?.SampleRate ?? 44100;

                var audioData = new byte[e.BytesRecorded];
                Array.Copy(e.Buffer, audioData, e.BytesRecorded);

                var eventArgs = new AudioDataEventArgs
                {
                    VolumeLevel = volumeLevel,
                    AudioData = audioData,
                    SampleRate = sampleRate,
                    Timestamp = DateTime.UtcNow
                };

                // Log every 100th data event to avoid spam
                if (_audioDataCount % 100 == 0)
                {
                    Debug.WriteLine($"[AudioCapture] Data #{_audioDataCount}: {e.BytesRecorded} bytes, Volume: {volumeLevel:F3}, Rate: {sampleRate}Hz");
                }

                AudioDataAvailable?.Invoke(this, eventArgs);
            }
            catch (Exception ex)
            {
                Debug.WriteLine($"[AudioCapture] Exception in OnDataAvailable: {ex.Message}");
            }
        }

        private void OnRecordingStopped(object? sender, StoppedEventArgs e)
        {
            lock (_lock)
            {
                _isCapturing = false;

                if (_capture != null)
                {
                    _capture.DataAvailable -= OnDataAvailable;
                    _capture.RecordingStopped -= OnRecordingStopped;
                    _capture.Dispose();
                    _capture = null;
                }
            }

            if (e.Exception != null)
            {
                Debug.WriteLine($"[AudioCapture] Recording stopped with error: {e.Exception.Message}");
            }
            else
            {
                Debug.WriteLine("[AudioCapture] Recording stopped normally");
            }
        }

        private static float CalculateVolumeLevel(byte[] buffer, int bytesRecorded)
        {
            if (bytesRecorded == 0)
                return 0f;

            long sum = 0;
            int sampleCount = bytesRecorded / 4; // 32-bit samples (4 bytes each)

            for (int i = 0; i < bytesRecorded - 3; i += 4)
            {
                var sample = BitConverter.ToInt32(buffer, i);
                sum += Math.Abs(sample);
            }

            if (sampleCount == 0)
                return 0f;

            var average = sum / (double)sampleCount;
            var normalizedLevel = (float)(average / int.MaxValue);

            return Math.Min(1.0f, normalizedLevel);
        }

        public void Dispose()
        {
            Dispose(true);
            GC.SuppressFinalize(this);
        }

        protected virtual void Dispose(bool disposing)
        {
            if (_disposed)
                return;

            if (disposing)
            {
                Stop();

                lock (_lock)
                {
                    _capture?.Dispose();
                    _capture = null;
                }
            }

            _disposed = true;
        }

        ~AudioCaptureService()
        {
            Dispose(false);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Drawing;
using System.Linq;
using System.Windows.Forms;
using AmbientEffectsEngine.Models;

namespace AmbientEffectsEngine.Services.Rendering.Effects
{
    public class SoftGlowEffect : IEffect
    {
        private readonly List<Form> _effectForms = new List<Form>();
        private bool _disposed = false;

        public string EffectId => "softglow";
        public string Name => "Soft Glow";
        public string Description => "Solid color ambient glow that responds to screen colors and audio intensity";

        public void Initialize(IEnumerable<DisplayMonitor> targetMonitors)
        {
            CleanupForms();

            foreach (var monitor in targetMonitors.Where(m => !m.IsPrimary))
            {
                var screen = Screen.AllScreens.FirstOrDefault(s => s.DeviceName == monitor.Id);
                if (screen != null)
                {
                    var form = CreateEffectForm(screen);
                    _effectForms.Add(form);
                }
            }
        }

        public void UpdateEffect(ProcessedData data)
        {
            if (_disposed || data == null) return;

            var color = data.DominantColor;
            var intensity = Math.Clamp(data.AudioIntensity, 0.0f, 1.0f);

            // Debug output
            System.Diagnostics.Debug.WriteLine($"SoftGlow Update: Color=({color.R},{color.G},{color.B}), Intensity={intensity:F2}");

            // Apply intensity to the color brightness, but ensure minimum visibility
            var minIntensity = 0.3f; // Always show at least 30% of the color
            var effectiveIntensity = Math.Max(intensity, minIntensity);

            var adjustedColor = Color.FromArgb(
                (int)(color.R * effectiveIntensity),
                (int)(color.G * effectiveIntensity),
                (int)(color.B * effectiveIntensity)
            );

            foreach (var form in _effectForms)
            {
                if (form != null && !form.IsDisposed)
                {
                    // Check if form handle is created before invoking
                    if (form.IsHandleCreated)
                    {
                        form.Invoke(new Action(() =>
                        {
                            form.BackColor = adjustedColor;
                        }));
                    }
                    else
                    {
                        // Directly set color if handle not created (safer for testing)
                        form.BackColor = adjustedColor;
                    }
                }
            }
        }

        public void Show()
        {
            foreach (var form in _effectForms.Where(f => f != null && !f.IsDisposed))
            {
                form.Show();
                form.WindowState = FormWindowState.Maximized;
            }
        }

        public void Hide()
        {
            foreach (var form in _effectForms.Where(f => f != null && !f.IsDisposed))
            {
                form.Hide();
            }
        }

        private Form CreateEffectForm(Screen screen)
        {
            var form = new Form
            {
                FormBorderStyle = FormBorderStyle.None,
                WindowState = FormWindowState.Maximized,
                TopMost = true,
                BackColor = Color.Black,
                ShowInTaskbar = false,
                StartPosition = FormStartPosition.Manual
            };

            // Position form on the target screen
            form.Location = screen.Bounds.Location;
            form.Size = screen.Bounds.Size;

            return form;
        }

        private void CleanupForms()
        {
            foreach (var form in _effectForms.Where(f => f != null && !f.IsDisposed))
            {
                form.Close();
                form.Dispose();
            }
            _effectForms.Clear();
        }

        public void Dispose()
        {
            if (!_disposed)
            {
                CleanupForms();
                _disposed = true;
            }
        }
    }
}

using System;
using System.Collections.Generic;
using AmbientEffectsEngine.Models;

namespace AmbientEffectsEngine.Services.Rendering.Effects
{
    /// <summary>
    /// Interface for visual effects that can be rendered on secondary monitors.
    /// This interface implements the Strategy pattern to allow different effect implementations.
    /// </summary>
    public interface IEffect : IDisposable
    {
        /// <summary>
        /// Gets the unique identifier for this effect type.
        /// </summary>
        string EffectId { get; }

        /// <summary>
        /// Gets the display name for this effect type.
        /// </summary>
        string Name { get; }

        /// <summary>
        /// Gets the description for this effect type.
        /// </summary>
        string Description { get; }

        /// <summary>
        /// Initializes the effect with the target monitors where it should be rendered.
        /// This method should create and configure all necessary UI elements.
        /// </summary>
        /// <param name="targetMonitors">The monitors where the effect should be displayed (excluding primary)</param>
        void Initialize(IEnumerable<DisplayMonitor> targetMonitors);

        /// <summary>
        /// Updates the effect with new processed data from the data processing service.
        /// This method is called in real-time as new audio and color data becomes available.
        /// </summary>
        /// <param name="data">The processed data containing dominant color and audio intensity</param>
        void UpdateEffect(ProcessedData data);

        /// <summary>
        /// Shows the effect on all target monitors.
        /// </summary>
        void Show();

        /// <summary>
        /// Hides the effect on all target monitors without disposing resources.
        /// </summary>
        void Hide();
    }
}

using System;
using System.Collections.Generic;
using System.Drawing;
using System.Drawing.Drawing2D;
using System.Linq;
using System.Windows.Forms;
using AmbientEffectsEngine.Models;

namespace AmbientEffectsEngine.Services.Rendering.Effects
{
    public class GenerativeVisualizerEffect : IEffect
    {
        private readonly List<VisualizerForm> _effectForms = new List<VisualizerForm>();
        private readonly List<Particle> _particles = new List<Particle>();
        private readonly object _particleLock = new object();
        private readonly Random _random = new Random();
        private readonly System.Windows.Forms.Timer _animationTimer = new System.Windows.Forms.Timer();
        private bool _disposed = false;

        private Color _currentDominantColor = Color.Blue;
        private float _currentAudioIntensity = 0.0f;
        private long _frameCount = 0;

        public string EffectId => "generativevisualizer";
        public string Name => "Generative Visualizer";
        public string Description => "Dynamic particle-based visualization that responds to audio intensity and screen colors";

        public GenerativeVisualizerEffect()
        {
            _animationTimer.Interval = 16; // ~60 FPS (1000ms/60 ≈ 16ms)
            _animationTimer.Tick += OnAnimationTick;
        }

        public void Initialize(IEnumerable<DisplayMonitor> targetMonitors)
        {
            CleanupForms();
            InitializeParticles();

            if (targetMonitors == null) return;

            foreach (var monitor in targetMonitors.Where(m => !m.IsPrimary))
            {
                var screen = Screen.AllScreens.FirstOrDefault(s => s.DeviceName == monitor.Id);
                if (screen != null)
                {
                    var form = CreateVisualizerForm(screen);
                    _effectForms.Add(form);
                }
            }

            _animationTimer.Start();
        }

        public void UpdateEffect(ProcessedData data)
        {
            if (_disposed || data == null) return;

            _currentDominantColor = data.DominantColor;
            _currentAudioIntensity = Math.Clamp(data.AudioIntensity, 0.0f, 1.0f);

            // Debug output
            System.Diagnostics.Debug.WriteLine($"GenerativeVisualizer Update: Color=({data.DominantColor.R},{data.DominantColor.G},{data.DominantColor.B}), Intensity={_currentAudioIntensity:F2}");

            // Update particle behavior based on audio intensity
            UpdateParticles();
        }

        public void Show()
        {
            foreach (var form in _effectForms.Where(f => f != null && !f.IsDisposed))
            {
                form.Show();
                form.WindowState = FormWindowState.Maximized;
            }
        }

        public void Hide()
        {
            foreach (var form in _effectForms.Where(f => f != null && !f.IsDisposed))
            {
                form.Hide();
            }
        }

        private void InitializeParticles()
        {
            lock (_particleLock)
            {
                _particles.Clear();

                // Use actual screen bounds instead of hardcoded values
                var screenBounds = _effectForms.FirstOrDefault()?.Bounds ?? new Rectangle(0, 0, 1920, 1080);

                // Create initial particle set
                for (int i = 0; i < 100; i++)
                {
                    _particles.Add(new Particle
                    {
                        X = _random.Next(0, screenBounds.Width),
                        Y = _random.Next(0, screenBounds.Height),
                        VelocityX = (float)(_random.NextDouble() * 4 - 2),
                        VelocityY = (float)(_random.NextDouble() * 4 - 2),
                        Size = (float)(_random.NextDouble() * 8 + 2),
                        Life = 1.0f,
                        MaxLife = (float)(_random.NextDouble() * 5 + 2)
                    });
                }
            }
        }

        private void UpdateParticles()
        {
            lock (_particleLock)
            {
                var speedMultiplier = 1.0f + (_currentAudioIntensity * 3.0f); // Speed increases with audio
                var spawnRate = (int)(_currentAudioIntensity * 10); // Spawn more particles with audio

                // Update existing particles
                for (int i = _particles.Count - 1; i >= 0; i--)
                {
                    var particle = _particles[i];

                    // Update position with speed multiplier
                    particle.X += particle.VelocityX * speedMultiplier;
                    particle.Y += particle.VelocityY * speedMultiplier;

                    // Update life (slower decay for longer visibility)
                    particle.Life -= 0.005f; // Slower decay than 60 FPS rate

                    // Remove dead particles
                    if (particle.Life <= 0)
                    {
                        _particles.RemoveAt(i);
                    }
                }

                // Spawn new particles based on audio intensity
                var screenBounds = _effectForms.FirstOrDefault()?.Bounds ?? new Rectangle(0, 0, 1920, 1080);
                for (int i = 0; i < spawnRate; i++)
                {
                    if (_particles.Count < 500) // Limit total particles for performance
                    {
                        _particles.Add(new Particle
                        {
                            X = _random.Next(0, screenBounds.Width),
                            Y = _random.Next(0, screenBounds.Height),
                            VelocityX = (float)(_random.NextDouble() * 6 - 3),
                            VelocityY = (float)(_random.NextDouble() * 6 - 3),
                            Size = (float)(_random.NextDouble() * 12 + 3),
                            Life = 1.0f,
                            MaxLife = (float)(_random.NextDouble() * 3 + 1)
                        });
                    }
                }
            }
        }

        private void OnAnimationTick(object sender, EventArgs e)
        {
            _frameCount++;

            foreach (var form in _effectForms.Where(f => f != null && !f.IsDisposed))
            {
                if (form.IsHandleCreated)
                {
                    try
                    {
                        form.Invoke(new Action(() => form.Invalidate()));
                    }
                    catch
                    {
                        // Ignore invoke errors during shutdown
                    }
                }
            }
        }

        private VisualizerForm CreateVisualizerForm(Screen screen)
        {
            var form = new VisualizerForm(this)
            {
                FormBorderStyle = FormBorderStyle.None,
                WindowState = FormWindowState.Maximized,
                TopMost = true,
                BackColor = Color.Black,
                ShowInTaskbar = false,
                StartPosition = FormStartPosition.Manual
            };

            // Position form on the target screen
            form.Location = screen.Bounds.Location;
            form.Size = screen.Bounds.Size;

            return form;
        }

        private void CleanupForms()
        {
            _animationTimer.Stop();

            foreach (var form in _effectForms.Where(f => f != null && !f.IsDisposed))
            {
                form.Close();
                form.Dispose();
            }
            _effectForms.Clear();
        }

        public void Dispose()
        {
            if (!_disposed)
            {
                CleanupForms();
                _animationTimer?.Dispose();
                _disposed = true;
            }
        }

        // Internal methods for the custom form to access
        internal void RenderParticles(Graphics graphics, Rectangle bounds)
        {
            if (_disposed) return;

            // Create a safe copy of particles to avoid collection modification issues
            List<Particle> particlesCopy;
            lock (_particleLock)
            {
                particlesCopy = new List<Particle>(_particles);
            }

            using (var brush = new SolidBrush(_currentDominantColor))
            {
                foreach (var particle in particlesCopy)
                {
                    // Ensure particle is within bounds
                    if (particle.X >= 0 && particle.X < bounds.Width && 
                        particle.Y >= 0 && particle.Y < bounds.Height)
                    {
                        // Ensure minimum visibility with better alpha calculation
                        var normalizedLife = Math.Clamp(particle.Life / particle.MaxLife, 0.0f, 1.0f);
                        var alpha = (int)(Math.Max(normalizedLife, 0.3f) * 255); // Minimum 30% alpha
                        var color = Color.FromArgb(alpha, _currentDominantColor.R, _currentDominantColor.G, _currentDominantColor.B);

                        using (var particleBrush = new SolidBrush(color))
                        {
                            var size = particle.Size * (particle.Life / particle.MaxLife);
                            graphics.FillEllipse(particleBrush, particle.X - size/2, particle.Y - size/2, size, size);
                        }
                    }
                }
            }

            // Add some connecting lines for extra visual complexity
            if (_currentAudioIntensity > 0.3f)
            {
                using (var pen = new Pen(Color.FromArgb(50, _currentDominantColor), 1))
                {
                    var nearbyParticles = particlesCopy.Where(p => p.Life > 0.5f).Take(50).ToList();
                    for (int i = 0; i < nearbyParticles.Count - 1; i++)
                    {
                        for (int j = i + 1; j < Math.Min(i + 5, nearbyParticles.Count); j++)
                        {
                            var p1 = nearbyParticles[i];
                            var p2 = nearbyParticles[j];
                            var distance = Math.Sqrt(Math.Pow(p1.X - p2.X, 2) + Math.Pow(p1.Y - p2.Y, 2));

                            if (distance < 100)
                            {
                                graphics.DrawLine(pen, p1.X, p1.Y, p2.X, p2.Y);
                            }
                        }
                    }
                }
            }
        }
    }

    // Custom form for rendering the visualizer
    internal class VisualizerForm : Form
    {
        private readonly GenerativeVisualizerEffect _effect;

        public VisualizerForm(GenerativeVisualizerEffect effect)
        {
            _effect = effect;
            SetStyle(ControlStyles.AllPaintingInWmPaint | 
                     ControlStyles.UserPaint | 
                     ControlStyles.DoubleBuffer | 
                     ControlStyles.ResizeRedraw, true);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.Clear(Color.Black);
            _effect.RenderParticles(e.Graphics, ClientRectangle);
        }
    }

    // Particle data structure
    internal class Particle
    {
        public float X { get; set; }
        public float Y { get; set; }
        public float VelocityX { get; set; }
        public float VelocityY { get; set; }
        public float Size { get; set; }
        public float Life { get; set; }
        public float MaxLife { get; set; }
    }
}
